const IDX: Map<string, number> = new Map(CITIES.map((c, i) => [c, i]));

export function getDistance(a: string, b: string): number | null {
  const i = IDX.get(a);
  const j = IDX.get(b);
  if (i === undefined || j === undefined) return null;
  if (i === j) return 0;
  const d = M[i]?.[j] ?? -1;
  if (d >= 0) return d;
  const d2 = M[j]?.[i] ?? -1;
  return d2 >= 0 ? d2 : null;
}